function courseSchedule(data) {
    const lines = data.trim().split('\n');
    const numCourses = parseInt(lines[0]);
    const prerequisites = [];

    for (let i = 1; i < lines.length; i++) {
        const nums = lines[i].split(' ').map(Number);
        for (let j = 0; j < nums.length; j += 2) {
            prerequisites.push([nums[j + 1], nums[j]]);
        }
    }

    function isValidOrder(order, prerequisites) {
        const taken = new Set();
        for (const course of order) {
            for (const [pre, post] of prerequisites) {
                if (post === course && !taken.has(pre)) {
                    return false;
                }
            }
            taken.add(course);
        }
        return true;
    }

    function generatePermutations(arr) {
        if (arr.length === 0) return [[]];
        const result = [];
        for (let i = 0; i < arr.length; i++) {
            const current = arr[i];
            const remaining = arr.slice(0, i).concat(arr.slice(i + 1));
            for (const perm of generatePermutations(remaining)) {
                result.push([current].concat(perm));
            }
        }
        return result;
    }

    const courses = Array.from({ length: numCourses }, (_, i) => i);
    const permutations = generatePermutations(courses);
    for (const order of permutations) {
        if (isValidOrder(order, prerequisites)) {
            return true;
        }
    }
    return false;
}

