import java.util.*;
class Solution {
    public boolean courseSchedule(int data) {
        int numCourses = data;
        List<List<Integer>> prerequisites = new ArrayList<>();
        for (int i = 0; i < numCourses; i++) {
            prerequisites.add(new ArrayList<>());
        }
        // Example prerequisites for testing, can be modified as needed
        prerequisites.get(1).add(0); // Course 1 depends on Course 0
        prerequisites.get(2).add(1); // Course 2 depends on Course 1
        prerequisites.get(3).add(2); // Course 3 depends on Course 2
        List<Integer> courseOrder = new ArrayList<>();
        for (int i = 0; i < numCourses; i++) {
            courseOrder.add(i);
        }
        return canFinish(numCourses, prerequisites, courseOrder);
    }
    private boolean canFinish(int numCourses, List<List<Integer>> prerequisites, List<Integer> courseOrder) {
        do {
            if (isValidOrder(courseOrder, prerequisites)) {
                return true;
            }
        }
        while (nextPermutation(courseOrder));
        return false;
    }
    private boolean isValidOrder(List<Integer> order, List<List<Integer>> prerequisites) {
        Set<Integer> completed = new HashSet<>();
        for (int course : order) {
            for (int pre : prerequisites.get(course)) {
                if (!completed.contains(pre)) {
                    return false;
                }
            }
            completed.add(course);
        }
        return true;
    }
    private boolean nextPermutation(List<Integer> nums) {
        int i = nums.size() - 2;
        while (i >= 0 && nums.get(i) >= nums.get(i + 1)) {
            i--;
        }
        if (i < 0) {
            return false;
        }
        int j = nums.size() - 1;
        while (nums.get(j) <= nums.get(i)) {
            j--;
        }
        Collections.swap(nums, i, j);
        Collections.reverse(nums.subList(i + 1, nums.size()));
        return true;
    }
}

