package main

import (
    "fmt"
    "sort"
)

func courseSchedule(data int) bool {
    prerequisites := [][]int{
        {1, 0},
        {2, 1},
        {3, 2},
    }
    courses := make([]int, data)
    for i := 0; i < data; i++ {
        courses[i] = i
    }
    return canFinish(courses, prerequisites)
}

func canFinish(courses []int, prerequisites [][]int) bool {
    n := len(courses)
    permute(courses, 0, n, prerequisites)
    return false
}

func permute(arr []int, l int, r int, prerequisites [][]int) bool {
    if l == r {
        if isValid(arr, prerequisites) {
            return true
        }
        return false
    }
    for i := l; i < r; i++ {
        arr[l], arr[i] = arr[i], arr[l]
        if permute(arr, l+1, r, prerequisites) {
            return true
        }
        arr[l], arr[i] = arr[i], arr[l]
    }
    return false
}

func isValid(order []int, prerequisites [][]int) bool {
    index := make(map[int]int)
    for i, course := range order {
        index[course] = i
    }
    for _, prereq := range prerequisites {
        if index[prereq[0]] < index[prereq[1]] {
            return false
        }
    }
    return true
}

func main() {
    fmt.Println(courseSchedule(4)) // Example usage
}

