public class Solution {
    public bool courseSchedule(int data) {
        int numCourses = data;
        List<int>[] graph = new List<int>[numCourses];
        for (int i = 0; i < numCourses; i++) {
            graph[i] = new List<int>();
        }
        int[,] prerequisites = new int[,] { { 1, 0 }, { 2, 1 }, { 3, 2 } }; // Example prerequisites

        foreach (var pre in prerequisites) {
            graph[pre[1]].Add(pre[0]);
        }

        List<int> order = new List<int>();
        bool[] visited = new bool[numCourses];
        bool[] recStack = new bool[numCourses];

        for (int i = 0; i < numCourses; i++) {
            if (!visited[i]) {
                if (IsCyclic(i, graph, visited, recStack)) {
                    return false;
                }
            }
        }
        return true;
    }

    private bool IsCyclic(int v, List<int>[] graph, bool[] visited, bool[] recStack) {
        visited[v] = true;
        recStack[v] = true;

        foreach (var neighbor in graph[v]) {
            if (!visited[neighbor]) {
                if (IsCyclic(neighbor, graph, visited, recStack)) {
                    return true;
                }
            } else if (recStack[neighbor]) {
                return true;
            }
        }
        recStack[v] = false;
        return false;
    }
}

